Rules.InvariantScript:
// reset controls
Reset(gal_Clone_Selection);
// clear variables
UpdateContext({locShowSaveButton: false});
// clear collections
ClearCollect(
    colCloneProperties,
    {
        Value: "",
        Attribute: "Room"
    }
);

// show the save button once all selections have been made
If(locCurrentCloneProperty="Quantity", UpdateContext({locShowSaveButton: true}););


// add the next window attribute to window properties
If(LookUp(colCloneProperties, Attribute=locCurrentCloneProperty, Value)="",
    Switch(locCurrentCloneProperty,
        "Room", Collect(colCloneProperties, {Attribute: "Quantity",ID: "", Value: ""})
    )
);

// change to the next window property
UpdateContext({locCurrentCloneProperty:
    Switch(locCurrentCloneProperty,
        "Room", "Quantity",
        "Quantity"
    )
});

// write the selection to the window property
Patch(colCloneProperties, LookUp(colCloneProperties, Attribute=gal_Clone_Selected.Selected.Attribute), {ID: ThisItem.ID, Value: Substitute(Left(ThisItem.Value, Find("Floor", ThisItem.Value)+4), Char(13),", ")});
Reset(gal_Clone_Selected);Reset(gal_Clone_Selection);

// store the job entry GUID to be cloned
UpdateContext({locCloneJobEntryGUID: gblRecordJobEntryCurrent_.'Job Entry'});
// create new job entry record
With(
    {
        varType: "colCdsJobEntries",
        varRecordRef: GUID()
    },
    Set(
        gblRecordJobEntryCurrent_,
        Patch(
            colCdsJobEntries,
            Defaults(colCdsJobEntries),
            {
                'Job Entry': varRecordRef,
                Job: LookUp(
                    colCdsJobs,
                    appJobIDText = gblRecordJobCurrent.appJobIDText
                ),
                'Window Choice': gblRecordJobEntryCurrent_.'Window Choice',
                appJobIdText: gblRecordJobCurrent.appJobIDText,
                'Job Entry Option (Header)': gblRecordJobEntryCurrent_.'Job Entry Option (Header)',
                Completed: gblOptionSets.JobEntry.Completed.No,
                'Room: Description': gblRecordJobEntryCurrent_.'Room: Description',
                'Room: Floor': gblRecordJobEntryCurrent_.'Room: Floor',
                'Room: Type': gblRecordJobEntryCurrent_.'Room: Type'
            }
        )
    );
    Collect(
        colAUDRecords,
        {
            Type: "colCdsJobEntries",
            RecordRef: varRecordRef,
            Job: gblRecordJobCurrent.Job,
            Operation: "A"
        }
    )
);
// add new job entries and job entry selections
ForAll(
    Filter(
        colCdsJobEntrySelections,
        'Job Entry'.'Job Entry' = locCloneJobEntryGUID
    ) As tblJobEntrySelections,
    With(
        {
            varType: "colCdsJobEntrySelections",
            varRecordRef: GUID()
        },
        Patch(
            colCdsJobEntrySelections,
            Defaults(colCdsJobEntrySelections),
            {
                Job: gblRecordJobCurrent,
                'Job Entry Selection': varRecordRef,
                'Job Entry': gblRecordJobEntryCurrent_,
                'Job Entry Option (Attribute)': tblJobEntrySelections[@'Job Entry Option (Attribute)'],
                'Job Entry Option (Value)': tblJobEntrySelections[@'Job Entry Option (Value)'],
                'Job Entry Option (Value) (Sales)': tblJobEntrySelections[@'Job Entry Option (Value) (Sales)']
            }
        );
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        )
    )
);
ForAll(
    Sequence(
        Value(
            LookUp(
                colCloneProperties,
                Attribute = "Quantity",
                Value
            )
        )
    ),
    With(
        {
            varType: "colCdsWindowMeasurements",
            varRecordRef: GUID()
        },
        Patch(
            colCdsWindowMeasurements,
            Defaults(colCdsWindowMeasurements),
            {
                Name: $"Tech 0{Char(34)} x 0{Char(34)}",
                'Exception?': gblOptionSets.WindowMeasurement.Exception.No,
                Height: 0,
                Job: gblRecordJobCurrent,
                'Job Entry': gblRecordJobEntryCurrent_,
                Type: gblOptionSets.WindowMeasurement.Type.Tech,
                'United Inches (UI)': 0,
                Width: 0,
                'Window Measurement': varRecordRef
            }
        );
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        )
    )
);
// create project sidebar
ClearCollect(
    colProjectSidebar,
    Ungroup(
        Table(
            {
                varMenuItems: RenameColumns(
                    Table(
                        {
                            ID: gblRecordJobEntryCurrent_.'Job Entry',
                            Name: Index(
                                ForAll(Split(
                                    gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                    " > "
                                ), {Result: ThisRecord.Value}),
                                2
                            ).Result,
                            Category: "Job Entry",
                            Description: Index(
                                ForAll(Split(
                                    gblRecordJobEntryCurrent_.'Window Choice'.Name,
                                    " > "
                                ), {Result: ThisRecord.Value}),
                                1
                            ).Result,
                            Screen: 'Windows Screen',
                            Type: "Window Choice",
                            Image: 'dblhungw-2',
                            ImageDisabled: 'dblhungw-2'
                        }
                    ),
                    Name,
                    Title
                )
            },
            {
                varMenuItems: ShowColumns(
                    RenameColumns(
                        AddColumns(
                            Filter(
                                colCdsWindowMeasurements,
                                'Job Entry'.'Job Entry' = gblRecordJobEntryCurrent_.'Job Entry',
                                Type = gblOptionSets.WindowMeasurement.Type.Tech,
                                Status <> gblOptionSets.WindowMeasurement.Status.Inactive
                            ),
                            Category,
                            "Window Measurement",
                            Description,
                            If(
                                And(
                                    'United Inches (UI)'=0,
                                    !IsBlank(gblRecordJobEntryCurrent_.'Measurement (Sales)')
                                ),
                                "Sales Measurement",
                                "Tech Measurement"
                            ),
                            Image,
                            gblAppIcons.Ruler,
                            ImageDisabled,
                            gblAppIcons.RulerDisabled,
                            Screen,
                            'Measure Window Screen',
                            Title,
                            If(
                                And(
                                    'United Inches (UI)'=0,
                                    !IsBlank(gblRecordJobEntryCurrent_.'Measurement (Sales)')
                                ),
                                $"{Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Width)}"" x {Text(gblRecordJobEntryCurrent_.'Measurement (Sales)'.Height)}""",
                                $"{RoundDown(Width, 0)} {Switch(
                                    Mod(Width, 1),
                                    0, "",
                                    0.125, "1/8",
                                    0.250, "1/4",
                                    0.375, "3/8",
                                    0.500, "1/2",
                                    0.625, "5/8",
                                    0.750, "3/4",
                                    0.875, "7/8"
                                )}"" x {RoundDown(Height, 0)} {Switch(
                                    Mod(Height, 1),
                                    0, "",
                                    0.125, "1/8",
                                    0.250, "1/4",
                                    0.375, "3/8",
                                    0.500, "1/2",
                                    0.625, "5/8",
                                    0.750, "3/4",
                                    0.875, "7/8"
                                )}"""
                            )
                        ),
                        'Window Measurement',
                        ID
                    ),
                    ID,
                    Title,
                    Category,
                    Description,
                    Screen,
                    Image,
                    ImageDisabled
                )
            }
        ),
        varMenuItems
    )
);
Set(
    gblProjectSidebarItemCurrent,
    First(colProjectSidebar)
);
//save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobEntries,
        "localCdsJobEntries"
    );
    SaveData(
        colCdsJobEntrySelections,
        "localCdsJobEntrySelections"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
);
// leave the screen and reset
Reset(gal_Clone_Selection);
// next screen
Navigate(
    'Windows Screen',
    BorderStyle.None
);
